    ) AS t(language_id, expected_version)
)
SELECT 
    vv.id AS video_variant_id,
    vv."videoId",
    vv."languageId",
    vv.version AS current_version,
    elv.expected_version,
    CASE 
        WHEN vv.version = elv.expected_version THEN 'OK'
        WHEN vv.version != elv.expected_version THEN 'VERSION_MISMATCH'
        WHEN elv.language_id IS NULL THEN 'LANGUAGE_NOT_IN_LIST'
        ELSE 'UNKNOWN'
    END AS status
FROM public."VideoVariant" vv
LEFT JOIN expected_language_versions elv ON vv."languageId" = elv.language_id
WHERE vv."videoId" = '1_jf-0-0'
ORDER BY 
    CASE 
        WHEN vv.version != elv.expected_version THEN 1
        WHEN elv.language_id IS NULL THEN 2
        ELSE 3
    END,
    vv.id ASC
LIMIT 1000;
